// =============================================================================
// Error Utilities
// =============================================================================

/**
 * Type guard to check if an error is an MmsError
 */
export function isMmsError(error: unknown): error is MmsError {
  return error instanceof MmsError;
}

/**
 * Convert unknown error to MmsError
 */
export function toMmsError(error: unknown): MmsError {
  if (isMmsError(error)) {
    return error;
  }

  if (error instanceof Error) {
    return new SystemError(error.message, {
      originalError: error.name,
      stack: error.stack,
    });
  }

  return new SystemError(String(error));
}

/**
 * Error code registry for reference
 */
export const ERROR_CODES = {
  // Validation
  BUS_001: 'Validation error',
  FILE_001: 'CSV validation error',
  FILE_002: 'File operation error',
  ROW_001: 'Row validation error',

  // Auth
  AUTH_001: 'Authentication required',
  AUTH_002: 'Token expired',
  AUTH_003: 'Invalid token',
  AUTH_010: 'Authorization denied',
  AUTH_011: 'Depot access denied',

  // Not Found
  BUS_010: 'Resource not found',
  BUS_011: 'Train not found',
  BUS_012: 'PM schedule not found',

  // Conflicts
  BUS_020: 'Resource conflict',
  BUS_021: 'Duplicate resource',
  BUS_022: 'Track conflict',
  EXT_001: 'Maximo lock conflict',

  // Business Rules
  BUS_030: 'Business rule violation',
  BUS_031: 'Compliance window violation',
  BUS_032: 'Material constraint violation',
  BUS_033: 'Service demand violation',

  // System
  SYS_001: 'Internal system error',
  SYS_002: 'Database error',
  SYS_003: 'Redis error',
  SYS_004: 'Queue error',
  SYS_010: 'Service unavailable',
  SYS_011: 'Operation timeout',

  // External
  EXT_010: 'External service error',
  EXT_011: 'Maximo connection error',
} as const;

/**
 * MMS Logging Configuration
 *
 * Structured logging with Pino for consistent log format across all services.
 * Features:
 * - JSON format in production
 * - Pretty print in development
 * - Sensitive field redaction
 * - Request ID propagation
 * - OpenTelemetry trace context
 *
 * @see specs/004-backend-specification.md Section 4.14
 */

import pino, { type Logger, type LoggerOptions } from 'pino';

const isDevelopment = process.env['NODE_ENV'] === 'development';

/**
 * Fields to redact from logs (prevents PII/secrets leakage)
 */
const REDACT_PATHS = [
  'password',
  'passwordHash',
  'password_hash',
  'token',
  'accessToken',
  'refreshToken',
  'apiKey',
  'api_key',
  'authorization',
  'cookie',
  'creditCard',
  'ssn',
  '*.password',
  '*.token',
  '*.apiKey',
  'req.headers.authorization',
  'req.headers.cookie',
];

/**
 * Base logger configuration
 */
const baseOptions: LoggerOptions = {
  level: process.env['LOG_LEVEL'] ?? (isDevelopment ? 'debug' : 'info'),
  redact: {
    paths: REDACT_PATHS,
    censor: '[REDACTED]',
  },
  formatters: {
    level: (label) => ({ level: label }),
    bindings: (bindings) => ({
      pid: bindings.pid,
      host: bindings.hostname,
      service: process.env['SERVICE_NAME'] ?? 'mms',
    }),
  },
  timestamp: pino.stdTimeFunctions.isoTime,
  base: {
    env: process.env['NODE_ENV'] ?? 'development',
  },
};

/**
 * Development transport (pretty print)
 */
const developmentTransport = {
  target: 'pino-pretty',
  options: {
    colorize: true,
    translateTime: 'HH:MM:ss.l',
    ignore: 'pid,hostname',
    singleLine: false,
  },
};

/**
 * Create the root logger instance
 */
function createLogger(): Logger {
  if (isDevelopment) {
    return pino({
      ...baseOptions,
      transport: developmentTransport,
    });
  }

  return pino(baseOptions);
}

/**
 * Root logger instance
 */
export const logger = createLogger();

/**
 * Create a child logger with additional context
 * Use for service-specific or request-specific logging
 */
export function createChildLogger(context: Record<string, unknown>): Logger {
  return logger.child(context);
}

/**
 * Create a request-scoped logger with trace context
 */
export function createRequestLogger(requestId: string, traceId?: string): Logger {
  return logger.child({
    requestId,
    ...(traceId && { traceId }),
  });
}

/**
 * Log level type
 */
export type LogLevel = 'trace' | 'debug' | 'info' | 'warn' | 'error' | 'fatal';

/**
 * Structured error logging helper
 */
export function logError(
  log: Logger,
  error: Error,
  context?: Record<string, unknown>
): void {
  const errObj: Record<string, unknown> = {
    message: error.message,
    name: error.name,
    stack: error.stack,
  };
  if (error.cause) {
    errObj.cause = error.cause;
  }
  log.error(
    {
      err: errObj,
      ...context,
    },
    error.message
  );
}

/**
 * Performance timing helper
 */
export function logTiming(
  log: Logger,
  operation: string,
  durationMs: number,
  context?: Record<string, unknown>
): void {
  const level: LogLevel = durationMs > 1000 ? 'warn' : 'info';
  log[level](
    {
      operation,
      durationMs,
      ...context,
    },
    `${operation} completed in ${durationMs}ms`
  );
}

export default logger;

