  }),
  webhookLastReceivedAt: new Gauge({
    name: 'mms_maximo_webhook_last_received_timestamp',
    help: 'Timestamp of last webhook received (Unix epoch)',
    labelNames: ['depot_id'] as const,
    registers: [registry],
  }),

  // Polling fallback metrics
  pollingTriggered: new Counter({
    name: 'mms_maximo_polling_triggered_total',
    help: 'Total number of polling jobs triggered',
    labelNames: ['trigger_reason'] as const,
    registers: [registry],
  }),
  pollingRecordsFound: new Counter({
    name: 'mms_maximo_polling_records_found_total',
    help: 'Total number of records found during polling',
    registers: [registry],
  }),
  pollingDuration: new Histogram({
    name: 'mms_maximo_polling_duration_seconds',
